import os
import shutil
from pathlib import Path

def backup_directory(source_dir, archive_name, format):
    validated_path = str(Path(source_dir).resolve())
    
    if format == 'tar.gz':
        subprocess.run(['tar', '-czf', archive_name, validated_path], check=True, shell=False)
    elif format == 'tar.bz2':
        subprocess.run(['tar', '-cjf', archive_name, validated_path], check=True, shell=False)
    elif format == 'zip':
        shutil.make_archive(archive_name.replace('.zip', ''), 'zip', validated_path)
    elif format == '7z':
        subprocess.run(['7z', 'a', archive_name, validated_path], check=True, shell=False)
    else:
        raise ValueError("Unsupported compression format")

# Example usage
backup_directory('/path/to/user/directory', '/path/to/backup/archive', 'tar.gz')